                <button onclick="setDirection(0,1)">⬇</button>
            </div>
        </div>

        <div class="controls-hint">P 暂停 | 方向键/WASD 移动 | 空格 开始/重启</div>
    </div>

    <script>
        const canvas = document.getElementById('gameCanvas');
        const ctx = canvas.getContext('2d');

        const GRID_SIZE = 20;
        const CELL_SIZE = canvas.width / GRID_SIZE;
        const INITIAL_SPEED = 150;
        const MIN_SPEED = 60;
        const SPEED_INCREASE = 3;

        let snake = [];
        let direction = { x: 1, y: 0 };
        let nextDirection = { x: 1, y: 0 };
        let foods = [];
        let score = 0;
        let highScore = parseInt(localStorage.getItem('snakeHighScore')) || 0;
        let gameState = 'start'; // start, playing, paused, gameover
        let gameLoop = null;
        let currentSpeed = INITIAL_SPEED;
        let particles = [];
        let gridPulse = 0;
        let combo = 0;
        let comboTimer = 0;
        let shakeAmount = 0;
        let floatingTexts = [];

        document.getElementById('highScore').textContent = highScore;

        // Particle class
        class Particle {
            constructor(x, y, color) {
                this.x = x;
                this.y = y;
                this.vx = (Math.random() - 0.5) * 8;
                this.vy = (Math.random() - 0.5) * 8;
                this.life = 1;
                this.decay = 0.02 + Math.random() * 0.03;
                this.size = 2 + Math.random() * 4;
                this.color = color;
            }

            update() {
                this.x += this.vx;
                this.y += this.vy;
                this.vx *= 0.96;
                this.vy *= 0.96;
                this.life -= this.decay;
            }

            draw() {
                ctx.save();
                ctx.globalAlpha = this.life;
                ctx.fillStyle = this.color;
                ctx.shadowBlur = 10;
                ctx.shadowColor = this.color;
                ctx.beginPath();
                ctx.arc(this.x, this.y, this.size * this.life, 0, Math.PI * 2);
                ctx.fill();
                ctx.restore();
            }
        }

        class FloatingText {
            constructor(x, y, text, color) {
                this.x = x;
                this.y = y;
                this.text = text;
                this.color = color;
                this.life = 1;
                this.vy = -2;
            }

            update() {
                this.y += this.vy;
                this.vy *= 0.95;
                this.life -= 0.02;
            }

            draw() {
                ctx.save();
                ctx.globalAlpha = this.life;
                ctx.fillStyle = this.color;
                ctx.font = 'bold 18px Arial';
                ctx.textAlign = 'center';
                ctx.shadowBlur = 10;
                ctx.shadowColor = this.color;
                ctx.fillText(this.text, this.x, this.y);
                ctx.restore();
            }
        }

        function initGame() {
            const startX = Math.floor(GRID_SIZE / 4);
            const startY = Math.floor(GRID_SIZE / 2);
            snake = [
                { x: startX, y: startY },
                { x: startX - 1, y: startY },
                { x: startX - 2, y: startY }
            ];
            direction = { x: 1, y: 0 };
            nextDirection = { x: 1, y: 0 };
            score = 0;
            currentSpeed = INITIAL_SPEED;
            foods = [];
            particles = [];
            floatingTexts = [];
            combo = 0;
            comboTimer = 0;
            shakeAmount = 0;
            document.getElementById('score').textContent = 0;
            document.getElementById('speed').textContent = 1;
            spawnFood();
        }

        function spawnFood() {
            // Keep 1-3 foods on screen
            while (foods.length < Math.min(1 + Math.floor(score / 100), 3)) {
                let pos;
                let attempts = 0;
                do {
                    pos = {
                        x: Math.floor(Math.random() * GRID_SIZE),
                        y: Math.floor(Math.random() * GRID_SIZE)
                    };
                    attempts++;
                } while ((isOnSnake(pos) || isOnFood(pos)) && attempts < 100);

                if (attempts < 100) {
                    const rand = Math.random();
                    let type = 'normal';
                    if (rand < 0.05) type = 'rainbow';
                    else if (rand < 0.2) type = 'golden';

                    foods.push({
                        x: pos.x,
                        y: pos.y,
                        type: type,
                        spawnTime: Date.now(),
                        pulse: 0
                    });
                }
            }
        }

        function isOnSnake(pos) {
            return snake.some(seg => seg.x === pos.x && seg.y === pos.y);
        }

        function isOnFood(pos) {
            return foods.some(f => f.x === pos.x && f.y === pos.y);
        }

        function update() {
            if (gameState !== 'playing') return;

            direction = { ...nextDirection };

            const head = {
                x: snake[0].x + direction.x,
                y: snake[0].y + direction.y
            };

            // Wall collision
            if (head.x < 0 || head.x >= GRID_SIZE || head.y < 0 || head.y >= GRID_SIZE) {
                gameOver();
                return;
            }

            // Self collision
            if (snake.some(seg => seg.x === head.x && seg.y === head.y)) {
                gameOver();
                return;
            }

            snake.unshift(head);

            // Food collision
            const foodIndex = foods.findIndex(f => f.x === head.x && f.y === head.y);
            if (foodIndex !== -1) {
                const food = foods[foodIndex];
                let points = 10;
                let particleColor = '#ff4444';

                if (food.type === 'golden') {
                    points = 30;
                    particleColor = '#ffd700';
                } else if (food.type === 'rainbow') {
                    points = 50;
                    particleColor = '#ff00ff';
                }

                // Combo system
                combo++;
                comboTimer = 120;
                if (combo > 1) {
                    points = Math.floor(points * (1 + combo * 0.2));
                }

                score += points;
                document.getElementById('score').textContent = score;

                // Floating text
                const px = head.x * CELL_SIZE + CELL_SIZE / 2;
                const py = head.y * CELL_SIZE + CELL_SIZE / 2;
                let text = `+${points}`;
                if (combo > 1) text += ` x${combo}连击!`;
                floatingTexts.push(new FloatingText(px, py, text, particleColor));

                // Spawn particles
                for (let i = 0; i < 20; i++) {
                    particles.push(new Particle(px, py, particleColor));
                }

                shakeAmount = 5;

                // Speed up
                const speedLevel = Math.floor(score / 50);
                currentSpeed = Math.max(MIN_SPEED, INITIAL_SPEED - speedLevel * SPEED_INCREASE);
                document.getElementById('speed').textContent = speedLevel + 1;

                foods.splice(foodIndex, 1);
                spawnFood();

                // Restart game loop with new speed
                clearInterval(gameLoop);
                gameLoop = setInterval(update, currentSpeed);
            } else {
                snake.pop();
                // Decrease combo timer
                if (comboTimer > 0) {
                    comboTimer--;
                } else {
                    combo = 0;
                }
            }
        }

        function gameOver() {
            gameState = 'gameover';
            clearInterval(gameLoop);

            // Explosion particles
            snake.forEach(seg => {
                for (let i = 0; i < 5; i++) {
                    particles.push(new Particle(
                        seg.x * CELL_SIZE + CELL_SIZE / 2,
                        seg.y * CELL_SIZE + CELL_SIZE / 2,
                        '#ff4444'
                    ));
                }
            });

            shakeAmount = 15;

            document.getElementById('finalScore').textContent = score;
            document.getElementById('finalLength').textContent = snake.length;

            const newRecordEl = document.getElementById('newRecord');
            if (score > highScore) {
                highScore = score;
                localStorage.setItem('snakeHighScore', highScore);
                document.getElementById('highScore').textContent = highScore;
                newRecordEl.style.display = 'block';
            } else {
                newRecordEl.style.display = 'none';
            }

            document.getElementById('gameOverOverlay').classList.remove('hidden');
        }

        function draw() {
            ctx.save();

            // Screen shake
            if (shakeAmount > 0) {
                const sx = (Math.random() - 0.5) * shakeAmount;
                const sy = (Math.random() - 0.5) * shakeAmount;
                ctx.translate(sx, sy);
                shakeAmount *= 0.9;
                if (shakeAmount < 0.5) shakeAmount = 0;
            }

            // Clear
            ctx.fillStyle = '#0d0d35';
            ctx.fillRect(0, 0, canvas.width, canvas.height);

            // Draw grid
            ctx.strokeStyle = 'rgba(255, 255, 255, 0.03)';
            ctx.lineWidth = 0.5;
            for (let i = 0; i <= GRID_SIZE; i++) {
                ctx.beginPath();
                ctx.moveTo(i * CELL_SIZE, 0);
                ctx.lineTo(i * CELL_SIZE, canvas.height);
                ctx.stroke();
                ctx.beginPath();
                ctx.moveTo(0, i * CELL_SIZE);
                ctx.lineTo(canvas.width, i * CELL_SIZE);
                ctx.stroke();
            }

            // Draw foods
            foods.forEach(food => {
                const px = food.x * CELL_SIZE + CELL_SIZE / 2;
                const py = food.y * CELL_SIZE + CELL_SIZE / 2;
                const elapsed = (Date.now() - food.spawnTime) / 1000;
                const pulse = 1 + Math.sin(elapsed * 4) * 0.15;
                const radius = (CELL_SIZE / 2 - 2) * pulse;

                ctx.save();

                if (food.type === 'normal') {
                    const gradient = ctx.createRadialGradient(px, py, 0, px, py, radius);
                    gradient.addColorStop(0, '#ff6b6b');
                    gradient.addColorStop(1, '#ee2222');
                    ctx.fillStyle = gradient;
                    ctx.shadowBlur = 15;
                    ctx.shadowColor = '#ff4444';
                } else if (food.type === 'golden') {
                    const gradient = ctx.createRadialGradient(px, py, 0, px, py, radius);
                    gradient.addColorStop(0, '#fff176');
                    gradient.addColorStop(1, '#ffd700');
                    ctx.fillStyle = gradient;
                    ctx.shadowBlur = 20;
                    ctx.shadowColor = '#ffd700';
                } else if (food.type === 'rainbow') {
                    const hue = (elapsed * 100) % 360;
                    ctx.fillStyle = `hsl(${hue}, 100%, 60%)`;
                    ctx.shadowBlur = 25;
                    ctx.shadowColor = `hsl(${hue}, 100%, 60%)`;
                }

                ctx.beginPath();
                ctx.arc(px, py, radius, 0, Math.PI * 2);
                ctx.fill();

                // Inner shine
                ctx.fillStyle = 'rgba(255, 255, 255, 0.3)';
                ctx.beginPath();
                ctx.arc(px - radius * 0.25, py - radius * 0.25, radius * 0.35, 0, Math.PI * 2);
                ctx.fill();

                ctx.restore();
            });

            // Draw snake
            snake.forEach((seg, index) => {
                const px = seg.x * CELL_SIZE;
                const py = seg.y * CELL_SIZE;
                const padding = 1;

                const t = index / snake.length;
                const r = Math.floor(0 + t * 0);
                const g = Math.floor(255 - t * 155);
                const b = Math.floor(136 - t * 80);

                ctx.save();

                if (index === 0) {
                    // Head
                    ctx.fillStyle = '#00ff88';
                    ctx.shadowBlur = 20;
                    ctx.shadowColor = '#00ff88';

                    const radius = CELL_SIZE / 2 - padding;
                    ctx.beginPath();
                    ctx.roundRect(px + padding, py + padding, CELL_SIZE - padding * 2, CELL_SIZE - padding * 2, 6);
                    ctx.fill();

                    // Eyes
                    ctx.shadowBlur = 0;
                    const eyeSize = 3;
                    const eyeOffset = CELL_SIZE * 0.25;
                    let eye1x, eye1y, eye2x, eye2y;

                    if (direction.x === 1) {
                        eye1x = px + CELL_SIZE * 0.7; eye1y = py + CELL_SIZE * 0.3;
                        eye2x = px + CELL_SIZE * 0.7; eye2y = py + CELL_SIZE * 0.7;
                    } else if (direction.x === -1) {
                        eye1x = px + CELL_SIZE * 0.3; eye1y = py + CELL_SIZE * 0.3;
                        eye2x = px + CELL_SIZE * 0.3; eye2y = py + CELL_SIZE * 0.7;
                    } else if (direction.y === -1) {
                        eye1x = px + CELL_SIZE * 0.3; eye1y = py + CELL_SIZE * 0.3;
                        eye2x = px + CELL_SIZE * 0.7; eye2y = py + CELL_SIZE * 0.3;
                    } else {
                        eye1x = px + CELL_SIZE * 0.3; eye1y = py + CELL_SIZE * 0.7;
                        eye2x = px + CELL_SIZE * 0.7; eye2y = py + CELL_SIZE * 0.7;
                    }

                    ctx.fillStyle = 'white';
                    ctx.beginPath();
                    ctx.arc(eye1x, eye1y, eyeSize + 1, 0, Math.PI * 2);
                    ctx.fill();
                    ctx.beginPath();
                    ctx.arc(eye2x, eye2y, eyeSize + 1, 0, Math.PI * 2);
                    ctx.fill();

                    ctx.fillStyle = '#0d0d35';
                    ctx.beginPath();
                    ctx.arc(eye1x + direction.x, eye1y + direction.y, eyeSize - 1, 0, Math.PI * 2);
                    ctx.fill();
                    ctx.beginPath();
                    ctx.arc(eye2x + direction.x, eye2y + direction.y, eyeSize - 1, 0, Math.PI * 2);
                    ctx.fill();
                } else {
                    // Body
                    ctx.fillStyle = `rgb(${r}, ${g}, ${b})`;
                    ctx.shadowBlur = 8;
                    ctx.shadowColor = `rgba(0, ${g}, ${b}, 0.5)`;

                    ctx.beginPath();
                    ctx.roundRect(px + padding + 1, py + padding + 1, CELL_SIZE - padding * 2 - 2, CELL_SIZE - padding * 2 - 2, 4);
                    ctx.fill();

                    // Subtle pattern
                    if (index % 2 === 0) {
                        ctx.fillStyle = 'rgba(255, 255, 255, 0.08)';
                        ctx.beginPath();
                        ctx.roundRect(px + padding + 3, py + padding + 3, CELL_SIZE - padding * 2 - 6, CELL_SIZE - padding * 2 - 6, 3);
                        ctx.fill();
                    }
                }

                ctx.restore();
            });

            // Draw particles
            particles.forEach(p => {
                p.update();
                p.draw();
            });
            particles = particles.filter(p => p.life > 0);

            // Draw floating texts
            floatingTexts.forEach(ft => {
                ft.update();
                ft.draw();
            });
            floatingTexts = floatingTexts.filter(ft => ft.life > 0);

            // Combo display
            if (combo > 1 && comboTimer > 0) {
                ctx.save();
                ctx.globalAlpha = Math.min(1, comboTimer / 30);
                ctx.fillStyle = '#ffd700';
                ctx.font = 'bold 24px Arial';
                ctx.textAlign = 'center';
                ctx.shadowBlur = 15;
                ctx.shadowColor = '#ffd700';
                ctx.fillText(`${combo}x 连击!`, canvas.width / 2, 40);
                ctx.restore();
            }

            // Pause overlay
            if (gameState === 'paused') {
                ctx.fillStyle = 'rgba(0, 0, 0, 0.5)';
                ctx.fillRect(0, 0, canvas.width, canvas.height);
                ctx.fillStyle = '#00ff88';
                ctx.font = 'bold 48px Arial';
                ctx.textAlign = 'center';
                ctx.fillText('⏸ 暂停', canvas.width / 2, canvas.height / 2);
                ctx.fillStyle = 'rgba(255, 255, 255, 0.6)';
                ctx.font = '20px Arial';
                ctx.fillText('按 P 继续', canvas.width / 2, canvas.height / 2 + 40);
            }

            ctx.restore();

            requestAnimationFrame(draw);
        }

        function setDirection(x, y) {
            if (gameState === 'start' || gameState === 'gameover') {
                startGame();
                return;
            }

            // Prevent reversing
            if (direction.x + x === 0 && direction.y + y === 0) return;

            nextDirection = { x, y };
        }

        function startGame() {
            document.getElementById('startOverlay').classList.add('hidden');
            document.getElementById('gameOverOverlay').classList.add('hidden');
            initGame();
            gameState = 'playing';
            gameLoop = setInterval(update, currentSpeed);
        }

        // Keyboard controls
        document.addEventListener('keydown', (e) => {
            switch (e.key) {
                case 'ArrowUp':
                case 'w':
                case 'W':
                    e.preventDefault();
                    setDirection(0, -1);
                    break;
                case 'ArrowDown':
                case 's':
                case 'S':
                    e.preventDefault();
                    setDirection(0, 1);
                    break;
                case 'ArrowLeft':
                case 'a':
                case 'A':
                    e.preventDefault();
                    setDirection(-1, 0);
                    break;
                case 'ArrowRight':
                case 'd':
                case 'D':
                    e.preventDefault();
                    setDirection(1, 0);
                    break;
                case ' ':
                    e.preventDefault();
                    if (gameState === 'start' || gameState === 'gameover') {
                        startGame();
                    }
                    break;
                case 'p':
                case 'P':
                    if (gameState === 'playing') {
                        gameState = 'paused';
                        clearInterval(gameLoop);
                    } else if (gameState === 'paused') {
                        gameState = 'playing';
                        gameLoop = setInterval(update, currentSpeed);
                    }
                    break;
            }
        });

        // Touch/click to start
        canvas.addEventListener('click', () => {
            if (gameState === 'start' || gameState === 'gameover') {
                startGame();
            }
        });

        // Swipe controls for mobile
        let touchStartX = 0;
        let touchStartY = 0;

        canvas.addEventListener('touchstart', (e) => {
            touchStartX = e.touches[0].clientX;
            touchStartY = e.touches[0].clientY;
        }, { passive: true });

        canvas.addEventListener('touchend', (e) => {
            if (gameState === 'start' || gameState === 'gameover') {
                startGame();
                return;
            }

            const dx = e.changedTouches[0].clientX - touchStartX;
            const dy = e.changedTouches[0].clientY - touchStartY;

            if (Math.abs(dx) < 10 && Math.abs(dy) < 10) return;

            if (Math.abs(dx) > Math.abs(dy)) {
                setDirection(dx > 0 ? 1 : -1, 0);
            } else {
                setDirection(0, dy > 0 ? 1 : -1);
            }
        }, { passive: true });

        // roundRect polyfill
        if (!CanvasRenderingContext2D.prototype.roundRect) {
            CanvasRenderingContext2D.prototype.roundRect = function (x, y, w, h, r) {
                if (typeof r === 'number') r = [r, r, r, r];
                this.moveTo(x + r[0], y);
                this.lineTo(x + w - r[1], y);
                this.quadraticCurveTo(x + w, y, x + w, y + r[1]);
